create table dirkspzm32.bde_pd_rueckverf_sel (
    sid           varchar2(2 char) not null enable,
    firma_nr      number,
    abfr_datum    date,
    abfr_id       number(*, 0) not null enable,
    lhm_id        varchar2(20 char),
    lte_id        varchar2(20 char),
    leitzahl      number(*, 5),
    charge_bez    varchar2(20 char),
    artikel_id    number(*, 0),
    abfr_typ      varchar2(2 char),
    abfr_enddatum date,
    li_nr_lief    varchar2(20 char),
    order_li_nr   number(*, 5)
);

alter table dirkspzm32.bde_pd_rueckverf_sel
    add constraint pk_bde_rueckverfolgumg_sel primary key ( sid,
                                                            abfr_id )
        using index enable;


